 218	static void begin_func(bparser *parser, bfuncinfo *finfo, bblockinfo *binfo)
 219	{
 220	    bvm *vm = parser->vm;
 221	    bproto *proto = be_newproto(vm);
 222	    var_setproto(vm->top, proto);
 223	    be_stackpush(vm);
 224	    be_vector_init(vm, &finfo->code, sizeof(binstruction));
 225	    proto->code = be_vector_data(&finfo->code);
 226	    proto->codesize = be_vector_capacity(&finfo->code);
 227	    be_vector_init(vm, &finfo->kvec, sizeof(bvalue));
 228	    proto->ktab = be_vector_data(&finfo->kvec);
 229	    proto->nconst = be_vector_capacity(&finfo->kvec);
 230	    be_vector_init(vm, &finfo->pvec, sizeof(bproto*));
 231	    proto->ptab = be_vector_data(&finfo->pvec);
 232	    proto->nproto = be_vector_capacity(&finfo->pvec);
 233	    proto->source = parser_source(parser);
 234	    finfo->local = be_list_new(vm);
 235	    var_setlist(vm->top, finfo->local);
 236	    be_stackpush(vm);
 237	    finfo->upval = be_map_new(vm);
 238	    var_setmap(vm->top, finfo->upval);
 239	    be_stackpush(vm);
 240	    finfo->prev = parser->finfo;
 241	    finfo->lexer = &parser->lexer;
 242	    finfo->proto = proto;
 243	    finfo->freereg = 0;
 244	    finfo->binfo = NULL;
 245	    finfo->pc = 0;
 246	    finfo->flags = 0;
 247	    parser->finfo = finfo;
 248	#if BE_DEBUG_RUNTIME_INFO
 249	    be_vector_init(vm, &finfo->linevec, sizeof(blineinfo));
 250	    proto->lineinfo = be_vector_data(&finfo->linevec);
 251	    proto->nlineinfo = be_vector_capacity(&finfo->linevec);
 252	#endif
 253	#if BE_DEBUG_VAR_INFO
 254	    be_vector_init(vm, &finfo->varvec, sizeof(bvarinfo));
 255	    proto->varinfo = be_vector_data(&finfo->varvec);
 256	    proto->nvarinfo = be_vector_capacity(&finfo->varvec);
 257	#endif
 258	    begin_block(finfo, binfo, 0);
 259	}
