260	void be_bytecode_save(bvm *vm, const char *filename, bproto *proto)
261	{
262	    void *fp = be_fopen(filename, "wb");
263	    if (fp == NULL) {
264	        bytecode_error(vm, be_pushfstring(vm,
265	            "can not open file '%s'.", filename));
266	    } else {
267	        save_header(fp);
268	        save_global_info(vm, fp);
269	        save_proto(vm, fp, proto);
270	        be_fclose(fp);
271	    }
272	}
