474	    case '=':
475	        next(lexer);
476	        return OptGE;
477	    case '>':
478	        next(lexer);
479	        return check_next(lexer, '=') ? OptRsfAssign : OptShiftR;
480	    default:
481	        return OptGT;
482	    }
