221	bstring *be_newstrn(bvm *vm, const char *str, size_t len)
222	{
223	    if (len <= SHORT_STR_MAX_LEN) {
224	#if BE_USE_PRECOMPILED_OBJECT
225	        bstring *s = find_conststr(str, len);
226	        return s ? s : newshortstr(vm, str, len);
227	#else
228	        return newshortstr(vm, str, len);
229	#endif
230	    }
231	    return be_newlongstr(vm, str, len); /* long string */
232	}
233	
234	void be_gcstrtab(bvm *vm)
235	{
236	    struct bstringtable *tab = &vm->strtab;
237	    int size = tab->size, i;
238	    for (i = 0; i < size; ++i) {
239	        bstring **list = tab->table + i;
240	        bstring *prev = NULL, *node, *next;
241	        for (node = *list; node; node = next) {
242	            next = next(node);
243	            if (!gc_isfixed(node) && gc_iswhite(node)) {
244	                free_sstring(vm, node);
245	                tab->count--;
246	                if (prev) { /* link list */
247	                    prev->next = cast(void*, next);
248	                } else {
249	                    *list = next;
250	                }
251	            } else {
252	                prev = node;
253	                gc_setwhite(node);
254	            }
255	        }
256	    }
257	    if (tab->count < size >> 2 && size > 8) {
258	        resize(vm, size >> 1);
259	    }
260	}
261	
262	uint32_t be_strhash(const bstring *s)
263	{
264	    if (gc_isconst(s)) {
265	        bcstring* cs = cast(bcstring*, s);
266	        if (cs->hash) {  /* if hash is null we need to compute it */
267	            return cs->hash;
268	        } else {
269	            return str_hash(cstr(s), str_len(s));
270	        }
271	    }
272	#if BE_USE_STR_HASH_CACHE
273	    if (s->slen != 255) {
274	        return cast(bsstring*, s)->hash;
275	    }
276	#endif
277	    return str_hash(str(s), str_len(s));
278	}
279	
280	const char* be_str2cstr(const bstring *s)
281	{
282	    be_assert(cast_str(s) != NULL);
283	    if (gc_isconst(s)) {
284	        return cstr(s);
285	    }
286	    if (s->slen == 255) {
287	        return lstr(s);
288	    }
289	    return sstr(s);
290	}
291	
292	void be_str_setextra(bstring *s, int extra)
293	{
294	    if (!gc_isconst(s)) {
295	        s->extra = cast(bbyte, extra);
296	    }
297	}

