106	static bstring* ins2str(bvm *vm, int idx)
107	{
108	    bstring *s = str_literal(vm, "tostring");
109	    binstance *obj = var_toobj(vm->reg + idx);
110	    /* get method 'tostring' */
111	    int type = be_instance_member(vm, obj, s, vm->top);
112	    be_incrtop(vm); /* push the obj::tostring to stack */
113	    if (basetype(type) != BE_FUNCTION) {
114	        bstring *name = be_class_name(be_instance_class(obj));
115	        char *sbuf = be_malloc(vm, (size_t)str_len(name) + 16);
116	        sprintf(sbuf, "<instance: %s()>", str(name));
117	        be_stackpop(vm, 1); /* pop the obj::tostring */
118	        s = be_newstr(vm, sbuf);
119	        be_free(vm, sbuf, (size_t)str_len(name) + 16);
120	    } else {
121	        *vm->top = vm->reg[idx];
122	        be_dofunc(vm, vm->top - 1, 1);
123	        be_stackpop(vm, 1); /* pop the obj::tostring */
124	        if (!var_isstr(vm->top)) { /* check the return value */
125	            const char *name = str(be_instance_name(obj));
126	            be_raise(vm, "runtime_error", be_pushfstring(vm,
127	                "the value of `%s::tostring()` is not a 'string'",
128	                strlen(name) ? name : "<anonymous>"));
129	        }
130	        s = var_tostr(vm->top);
131	    }
132	    return s;
133	}
