230	/*******************************************************************
231	 * the function be_str2int():
232	 * >>-+------------+--+-----+----digits----><
233	 *    '-whitespace-'  +- + -+
234	 *                    '- - -'
235	 *******************************************************************/
236	BERRY_API bint be_str2int(const char *str, const char **endstr)
237	{
238	    int c, sign;
239	    bint sum = 0;
240	    skip_space(str);
241	    sign = c = *str++;
242	    if (c == '+' || c == '-') {
243	        c = *str++;
244	    }
245	    while (is_digit(c)) {
246	        sum = sum * 10 + c - '0';
247	        c = *str++;
248	    }
249	    if (endstr) {
250	        *endstr = str - 1;
251	    }
252	    return sign == '-' ? -sum : sum;
253	}
254	
255	/*******************************************************************
256	 * the function be_str2real():
257	 * >>-+------------+--+-----+--+-digits--+---+--+--------+-+------->
258	 *    '-whitespace-'  +- + -+  |         '-.-'  '-digits-' |   
259	 *                    '- - -'  '-.--digits-----------------'   
260	 * 
261	 * >--+------------------------+----------------------------------><
262	 *    '-+-e-+--+-----+--digits-'   
263	 *      '-E-'  +- + -+             
264	 *             '- - -'  
265	 *******************************************************************/
266	BERRY_API breal be_str2real(const char *str, const char **endstr)
267	{
268	    int c, sign;
269	    breal sum = 0, deci = 0, point = (breal)0.1;
270	    skip_space(str);
271	    sign = c = *str++;
272	    if (c == '+' || c == '-') {
273	        c = *str++;
274	    }
275	    while (is_digit(c)) {
276	        sum = sum * 10 + c - '0';
277	        c = *str++;
278	    }
279	    if (c == '.') {
280	        c = *str++;
281	        while (is_digit(c)) {
282	            deci = deci + ((breal)c - '0') * point;
283	            point *= (breal)0.1;
284	            c = *str++;
285	        }
286	    }
287	    sum = sum + deci;
288	    if (c == 'e' || c == 'E') {
289	        int e = 0;
290	        breal ratio = (c = *str++) == '-' ? (breal)0.1 : 10;
291	        if (c == '+' || c == '-') {
292	            c = *str++;
293	        }
294	        while (is_digit(c)) {
295	            e = e * 10 + c - '0';
296	            c = *str++;
297	        }
298	        while (e--) {
299	            sum *= ratio;
300	        }
301	    }
302	    if (endstr) {
303	        *endstr = str - 1;
304	    }
305	    return sign == '-' ? -sum : sum;
306	}
