294	bvalue* be_module_bind(bvm *vm, bmodule *module, bstring *attr)
295	{
296	    bmap *attrs = module->table;
297	    if (!gc_isconst(attrs)) {
298	        bvalue *v = be_map_findstr(vm, attrs, attr);
299	        if (v == NULL) {
300	            v = be_map_insertstr(vm, attrs, attr, NULL);
301	        }
302	        return v;
303	    }
304	    return NULL;
305	}
