307	const char* be_module_name(bmodule *module)
308	{
309	    if (gc_isconst(module)) {
310	        return module->info.name;
311	    }
312	    if (gc_exmark(module) & BE_MODULE_NAME) {
313	        return str(module->info.sname);
314	    }
315	    if (module->info.native) {
316	        return module->info.native->name;
317	    }
318	    return NULL;
319	}
320	
321	bbool be_module_setname(bmodule *module, bstring *name)
322	{
323	    if (!gc_isconst(module)) {
324	        module->info.sname = name;
325	        gc_setexmark(module, BE_MODULE_NAME);
326	        return btrue;
327	    }
328	    return bfalse;
329	}
