356	#if BE_USE_SHARED_LIB
357	
358	#if defined(__POSIX_OS__)
359	#include <dlfcn.h>
360	
361	#if defined(__GNUC__)
362	  #define cast_func(f) (__extension__(bntvfunc)(f))
363	#else
364	  #define cast_func(f) ((bntvfunc)(f))
365	#endif
366	
367	/* load shared library */
368	BERRY_API int be_loadlib(bvm *vm, const char *path)
369	{
370	    void *handle = dlopen(path, RTLD_LAZY);
371	    bntvfunc func = cast_func(dlsym(handle, "berry_export"));
372	    if (func == NULL) {
373	        return BE_IO_ERROR;
374	    }
375	    be_pushntvfunction(vm, func);
376	    return BE_OK;
377	}
378	#elif defined(_WIN32)
379	#include<wtypes.h>
380	#include <winbase.h>
381	
382	BERRY_API int be_loadlib(bvm *vm, const char *path)
383	{
384	    HINSTANCE handle = LoadLibrary(path);
385	    if (handle) {
386	        union {
387	            FARPROC proc;
388	            bntvfunc func;
389	        } u;
390	        u.proc = GetProcAddress(handle, "berry_export");
391	        if (u.func != NULL) {
392	            be_pushntvfunction(vm, u.func);
393	            return BE_OK;
394	        }
395	    }
396	    return BE_IO_ERROR;
397	}
398	#else
399	BERRY_API int be_loadlib(bvm *vm, const char *path)
400	{
401	    (void)vm, (void)path;
402	    return BE_IO_ERROR;
403	}
404	#endif
405	
406	#endif /* BE_USE_SHARED_LIB */

